module register_adder(
    input clk, rst, load,
    input [7:0] D,
    output reg [7:0] Q
);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk) begin
    if (rst) begin
        Q <= 8'b0;
    end else if (load) begin
        Q <= D;
    end else begin
        Q <= Q + D;
    end
end

endmodule
